import{_ as r,c as t,o as a,ai as o}from"./chunks/framework.TS84ywiI.js";const i="/assets/article-demo.NkmVGfkO.png",s="/assets/wechat-group-for-doocs.Zd_72pb4.png",g=JSON.parse('{"title":"Doocs 的公众号来了","description":"","frontmatter":{},"headers":[],"relativePath":"extra-page/subscriptions-for-doocs.md","filePath":"extra-page/subscriptions-for-doocs.md"}'),l={name:"extra-page/subscriptions-for-doocs.md"};function n(c,e,p,h,m,f){return a(),t("div",null,e[0]||(e[0]=[o('<h1 id="doocs-的公众号来了" tabindex="-1">Doocs 的公众号来了 <a class="header-anchor" href="#doocs-的公众号来了" aria-label="Permalink to &quot;Doocs 的公众号来了&quot;">​</a></h1><p>GitHub 开源社区 Doocs 旗下唯一公众号“<strong>Doocs</strong>”，专注于挖掘 IT 技术知识，助力开发者成长。</p><div style="text-align:center;"><img src="https://cdn-doocs.oss-cn-shenzhen.aliyuncs.com/gh/doocs/images/qrcode-for-doocs.png" style="width:200px;"><br></div><p>来成为公众号的首批粉丝吗？一定不会辜负你们的期待。</p><h2 id="为什么选择公众号" tabindex="-1">为什么选择公众号？ <a class="header-anchor" href="#为什么选择公众号" aria-label="Permalink to &quot;为什么选择公众号？&quot;">​</a></h2><p>微信公众号的<strong>原创保护功能</strong>做得比较好，内容阅读也比较方便。</p><p>后续我的所有原创文章，将第一时间通过微信公众号“Doocs”发布。如果其他公众号号主希望转载内容，请在公众号聊天窗口处发消息与我说明，或者直接添加我的个人微信(YLB0109)进行交流。</p><h2 id="公众号的定位是怎样的" tabindex="-1">公众号的定位是怎样的？ <a class="header-anchor" href="#公众号的定位是怎样的" aria-label="Permalink to &quot;公众号的定位是怎样的？&quot;">​</a></h2><ul><li><strong>内容高质</strong>：不随意从网上复制粘贴一些文章，即便是转载的技术文章，也要确保质量。</li><li><strong>定期更新</strong>：尽量在每周输出 1-2 篇文章，保证一定的更新频率。</li></ul><div style="text-align:center;"><img src="'+i+'" width="300px; "></div><h2 id="目前都有哪些文章" tabindex="-1">目前都有哪些文章？ <a class="header-anchor" href="#目前都有哪些文章" aria-label="Permalink to &quot;目前都有哪些文章？&quot;">​</a></h2><p>因为刚刚推出公众号，目前有以下几篇文章，来先睹为快吧：</p><ul><li><a href="https://mp.weixin.qq.com/s/Mo_knIRBQQL2s-D2aieZLg" target="_blank" rel="noreferrer">硬核！亿级流量秒杀系统设计</a></li><li><a href="https://mp.weixin.qq.com/s/fNiUmbY395rsPdEC0QDIrw" target="_blank" rel="noreferrer">技术面试是否要看面经？面试官/面试者有话说！</a></li><li><a href="https://mp.weixin.qq.com/s/Fsl6qYN5Dw4s6Du893MkFQ" target="_blank" rel="noreferrer">如何破解极验滑动验证码？成功率 100%！</a></li><li><a href="https://mp.weixin.qq.com/s/0HhgHLo_tTRFZcC-CVjDbw" target="_blank" rel="noreferrer">免费且好用的图床，就你了，「图壳」！</a></li><li><a href="https://mp.weixin.qq.com/s/RNKDCK2KoyeuMeEs6GUrow" target="_blank" rel="noreferrer">阿里又一个 20k+ stars 开源项目诞生，恭喜 fastjson！</a></li><li><a href="https://mp.weixin.qq.com/s/rjGqxUvrEqJNlo09GrT1Dw" target="_blank" rel="noreferrer">刷掉 90% 候选人的互联网大厂海量数据面试题（附题解 + 方法总结）</a></li><li><a href="https://mp.weixin.qq.com/s/kalGv5T8AZGxTnLHr2wDsA" target="_blank" rel="noreferrer">好用！期待已久的文本块功能究竟如何在 Java 13 中发挥作用？</a></li><li><a href="https://mp.weixin.qq.com/s/_q812aGD1b9QvZ2WFI0Qgw" target="_blank" rel="noreferrer">2019 GitHub 开源贡献排行榜新鲜出炉！微软谷歌领头，阿里跻身前 12！</a></li><li><a href="https://mp.weixin.qq.com/s/YlMISSc3Sn890BzTLytcLA" target="_blank" rel="noreferrer">Google 搜索的即时自动补全功能究竟是如何“工作”的？</a></li><li><a href="https://mp.weixin.qq.com/s/lpZ7eRdImy0MyTEVH68HYw" target="_blank" rel="noreferrer">厉害了，原来 Redisson 这么好用！</a></li><li><a href="https://mp.weixin.qq.com/s/47A_iXY_nArURwUTPHr2IQ" target="_blank" rel="noreferrer">一文带你搞懂 “缓存策略”</a></li><li><a href="https://mp.weixin.qq.com/s/TZqcAw7NTlcvU-p930-eHA" target="_blank" rel="noreferrer">Java Getter/Setter “防坑指南”</a></li><li><a href="https://mp.weixin.qq.com/s/Lok0epqn91Q51ygZo_FLkg" target="_blank" rel="noreferrer">太棒了，GitHub Review 代码能力小升级</a></li><li><a href="https://mp.weixin.qq.com/s/w1r-M6YVvQSfUtzO_xe44Q" target="_blank" rel="noreferrer">巧用 Redis Hyperloglog，轻松统计 UV 数据</a></li><li><a href="https://mp.weixin.qq.com/s/byxAjr3-ifWfDYQcR7YA8Q" target="_blank" rel="noreferrer">如何开启「GitHub+码云」双工作流模式？</a></li></ul><p>后续将推出一系列原创干货文章，敬请期待。</p><h2 id="是否有交流群" tabindex="-1">是否有交流群？ <a class="header-anchor" href="#是否有交流群" aria-label="Permalink to &quot;是否有交流群？&quot;">​</a></h2><p>有的，目前微信群“<strong>Doocs 的技术朋友们</strong>”已经接近 200 号人，如果你希望加入，请通过微信与我联系。</p><p><strong>注意</strong>，群内禁止一切垃圾广告信息，包括小程序助力信息、小游戏、社群推广、公众号推广、支付宝推广码等；交流 GitHub、开发相关，可以自由分享一些开发相关知识，但不提倡整天水群，建议还是多花点时间提升自己。</p><div style="text-align:center;"><img src="'+s+'" width="300px; "></div>',18)]))}const _=r(l,[["render",n]]);export{g as __pageData,_ as default};
